"use client";

export interface Category {
  id: string;
  name: string;
  slug: string;
  icon: string;
}

export interface Listing {
  id: string;
  title: string;
  description: string;
  images: string[];
  categoryId: string;
  sellerId: string;
  type: "AUCTION" | "BUY_NOW" | "HYBRID";
  startPrice: number;
  currentPrice: number;
  buyNowPrice: number | null;
  bidStep: number;
  status: string;
  endDate: string;
  deliveryOptions: string[];
  bidsCount: number;
  createdAt: string;
}

export const apiService = {
  async getCategories(): Promise<Category[]> {
    try {
      const res = await fetch("/api/listings");
      if (!res.ok) throw new Error("Помилка завантаження категорій");
      const data = await res.json();
      return data.categories || [];
    } catch {
      return [];
    }
  },

  async getListings(): Promise<Listing[]> {
    try {
      const res = await fetch("/api/listings");
      if (!res.ok) throw new Error("Помилка завантаження лотів");
      const data = await res.json();
      return data.listings || [];
    } catch {
      return [];
    }
  },

  async getListingById(id: string): Promise<Listing | null> {
    try {
      const res = await fetch(`/api/listings/${id}`);
      if (!res.ok) return null;
      const data = await res.json();
      return data.listing || null;
    } catch {
      return null;
    }
  },

  async createListing(listingData: Record<string, unknown>): Promise<Listing> {
    const res = await fetch("/api/listings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(listingData),
    });
    if (!res.ok) {
      const err = await res.json();
      throw new Error(err.error || "Помилка створення лоту");
    }
    const data = await res.json();
    return data.listing;
  },

  async getBids(listingId: string) {
    try {
      const res = await fetch(`/api/bids?listingId=${listingId}`);
      if (!res.ok) return [];
      const data = await res.json();
      return data.bids || [];
    } catch {
      return [];
    }
  },

  async placeBid(listingId: string, _bidderId: string, _bidderName: string, amount: number) {
    try {
      const res = await fetch("/api/bids", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ listingId, bidderId: _bidderId, amount }),
      });
      const data = await res.json();
      if (!res.ok) return { success: false, error: data.error || "Помилка здійснення ставки" };
      return { success: true, bid: data.bid };
    } catch (e) {
      return { success: false, error: String(e) };
    }
  },

  async buyNow(listingId: string, buyerId: string, deliveryProvider: string) {
    try {
      const res = await fetch("/api/transactions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ listingId, buyerId, deliveryProvider }),
      });
      const data = await res.json();
      if (!res.ok) return { success: false, error: data.error || "Помилка викупу лоту" };
      return { success: true, transaction: data.transaction };
    } catch (e) {
      return { success: false, error: String(e) };
    }
  },

  async getMessages(listingId: string, user1: string, user2: string) {
    try {
      const res = await fetch(`/api/messages?listingId=${listingId}&user1=${user1}&user2=${user2}`);
      if (!res.ok) return [];
      const data = await res.json();
      return data.messages || [];
    } catch {
      return [];
    }
  },

  async sendMessage(listingId: string, senderId: string, receiverId: string, text: string) {
    const res = await fetch("/api/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ listingId, senderId, receiverId, text }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || "Помилка надсилання повідомлення");
    return { message: data.message, warning: data.warning };
  },

  async getNotifications(userId: string) {
    try {
      const res = await fetch(`/api/notifications?userId=${userId}`);
      if (!res.ok) return [];
      const data = await res.json();
      return data.notifications || [];
    } catch {
      return [];
    }
  },

  async addNotification(userId: string, text: string, type = "INFO") {
    const res = await fetch("/api/notifications", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, text, type }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error || "Помилка додавання сповіщення");
    return data.notification;
  },

  async markNotificationsAsRead(userId: string) {
    try {
      await fetch("/api/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId, markAllAsRead: true }),
      });
    } catch {
      // silent
    }
  },

  async getTransactions(userId: string) {
    try {
      const res = await fetch(`/api/transactions?userId=${userId}`);
      if (!res.ok) return [];
      const data = await res.json();
      return data.transactions || [];
    } catch {
      return [];
    }
  },

  async getLeaderboard() {
    try {
      const res = await fetch("/api/leaderboard");
      if (!res.ok) return [];
      const data = await res.json();
      return data.leaderboard || [];
    } catch {
      return [];
    }
  },
};
